  ('bookkeeper-moex-01338', 'bookkeeper', 'bookkeeper-moex-104-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '下列何者非屬行政處分之要素？ 公法行為    行政機關之行為 具體及抽象事件所為之行為  對外直接發生法律效果', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "905d3fabe5f9", "answer_pdf_sha1": "03ba1485918e", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1201", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 49, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
