  ('bookkeeper-moex-01354', 'bookkeeper', 'bookkeeper-moex-103-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司X1年1月1日備抵壞帳餘額為$14,000（貸餘），當年度沖銷壞帳為$6,000，收回沖銷的壞帳 為$2,000。根據以往經驗，期末應收帳款的 5%會成為壞帳，甲公司 X1 年 12 月 31 日的應收帳款為 $300,000。則X1年度的壞帳費用為：', '["$15,000", "$11,000", "$9,000", "$5,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "eb7c2b3095ad", "answer_pdf_sha1": "151da49cfd80", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01355', 'bookkeeper', 'bookkeeper-moex-103-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司購置機器一部，買價$560,000，另付安裝費及試車費$60,000，採直線法折舊，估計可用 6 年，殘 值為$20,000，使用滿三年後，於第四年初發現機器僅能再用2年，且無殘值，則第四年終應計提折舊：', '["$100,000", "$130,000", "$150,000", "$160,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "eb7c2b3095ad", "answer_pdf_sha1": "151da49cfd80", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01356', 'bookkeeper', 'bookkeeper-moex-103-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司從民國97年至99年間進行新產品的研發，於99年底時該專利產生之無形資產符合定義及認列條 件，在此之前，於97年至99年間每年花費$100,000。99年底向政府申請專利權另耗費$50,000，則專利 權無形資產之入帳成本為：', '["$50,000", "$150,000", "$300,000", "$350,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "eb7c2b3095ad", "answer_pdf_sha1": "151da49cfd80", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
